        self.kind = kind
        self.authorPubkey = authorPubkey
        self.authorDisplayName = authorDisplayName
        self.authorPictureUrl = authorPictureUrl
        self.createdAt = createdAt
        self.content = content
        self.tags = tags
        self.altText = altText
    }
