/// Full envelope mirror of `nmp_content::embed_projection::EmbeddedEventEnvelope`.
public struct EmbeddedEventEnvelope: Equatable {
    /// The original nostr: URI (nevent1… / naddr1… / npub1…).
    public let uri: String
    /// Primary identifier: event-id hex for event-addressed refs, or
    /// `"kind:pubkey:d"` coordinate string for addressable events.
    public let primaryId: String
    /// Recursion guard state. Currently surfaced as defaults; reserved for
    /// nested-embed depth limits.
    public let depth: UInt8
    public let maxDepth: UInt8
    /// Kind-dispatched projection — drives which native renderer is chosen.
    public let projection: EmbedKindProjection
    /// Whether this embed should be collapsed (depth limit, cycle, unsupported).
    public let collapsed: Bool
    /// Optional machine-readable collapse reason.
    public let collapseReason: String?

    public init(
        uri: String,
        primaryId: String,
        depth: UInt8 = 0,
        maxDepth: UInt8 = 4,
        projection: EmbedKindProjection,
        collapsed: Bool = false,
        collapseReason: String? = nil
    ) {
        self.uri = uri
        self.primaryId = primaryId
        self.depth = depth
        self.maxDepth = maxDepth
        self.projection = projection
        self.collapsed = collapsed
        self.collapseReason = collapseReason
    }
}

import SwiftUI

/// Visual chrome shared by every kind-dispatched embed renderer.
///
/// Mirrors the TUI's `EmbedChromeContainer`: a left accent stripe whose color
/// deepens with nesting depth, plus a small indent so embedded content reads
/// as a child of the surrounding paragraph. The renderer itself draws inside
/// `content` — chrome knows nothing about the embedded kind.
public struct EmbedChromeContainer<Content: View>: View {
    public var depth: UInt8
    public var collapsed: Bool
    public var content: () -> Content

    public init(
        depth: UInt8 = 0,
        collapsed: Bool = false,
        @ViewBuilder content: @escaping () -> Content
    ) {
        self.depth = depth
        self.collapsed = collapsed
        self.content = content
    }

    public var body: some View {
        HStack(alignment: .top, spacing: 10) {
            RoundedRectangle(cornerRadius: 1.5)
                .fill(accentColor)
                .frame(width: 3)
                .frame(maxHeight: .infinity)
            content()
                .frame(maxWidth: .infinity, alignment: .leading)
        }
        .padding(.leading, CGFloat(depth) * 8)
        .padding(.vertical, 4)
    }

    /// Depth-graded accent. Matches the TUI's `Rgb(140, 160 + 8·depth, 220)`
    /// blueish ramp; collapsed embeds dim out.
    private var accentColor: Color {
        if collapsed {
            return Color(red: 100/255, green: 100/255, blue: 110/255)
        }
        let green = min(200, 160 + Int(depth) * 8)
        return Color(
            red: 140/255,
            green: Double(green) / 255,
            blue: 220/255
        )
    }
}

import SwiftUI

/// Renderer protocol for one `EmbedKindProjection` variant (or a group of
/// unknown numeric kinds). Mirrors the TUI's `KindRenderer` trait — the body
/// is the SwiftUI view emitted for the projection.
///
/// Implementations are `@MainActor` because they read SwiftUI environment
/// state through the `NostrContentRenderer` injected into the view tree.
@MainActor
public protocol KindRenderer {
    /// Render the projection into a SwiftUI view.
    ///
    /// `registry` is provided so recursive kind dispatch is possible (e.g. an
    /// article renderer that wants to nest a short-note preview through the
    /// same dispatch path).
    func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView
}

/// Single source of truth for kind → SwiftUI renderer dispatch on iOS.
///
/// Built up via `set_*` setters or `register_unknown(kind:)`; consulted by
/// `EmbeddedEvent` (and by `NostrContentView` when it walks an `EventRef`
/// node). Mirrors the TUI's `NostrKindRegistry` shape so apps porting
/// renderers from the terminal can do so 1:1.
@MainActor
public final class NostrKindRegistry: ObservableObject {
    private var shortNote: KindRenderer?
    private var article: KindRenderer?
    private var highlight: KindRenderer?
    private var profile: KindRenderer?
    private var unknownByKind: [UInt32: KindRenderer] = [:]
    private var fallback: KindRenderer

    public init(fallback: KindRenderer = DefaultUnknownRenderer()) {
        self.fallback = fallback
    }

    /// Returns a registry pre-populated with the built-in defaults for every
    /// known projection variant. Replace any slot via `setArticle(...)` /
    /// `setShortNote(...)` to swap in a richer handler.
    public static func makeDefault() -> NostrKindRegistry {
        let reg = NostrKindRegistry()
        reg.shortNote = DefaultShortNoteRenderer()
        reg.article = DefaultArticleRenderer()
        reg.highlight = DefaultHighlightRenderer()
        reg.profile = DefaultProfileRenderer()
        return reg
    }

    public func setShortNote(_ renderer: KindRenderer) { shortNote = renderer }
    public func setArticle(_ renderer: KindRenderer) { article = renderer }
    public func setHighlight(_ renderer: KindRenderer) { highlight = renderer }
    public func setProfile(_ renderer: KindRenderer) { profile = renderer }
    public func registerUnknown(kind: UInt32, renderer: KindRenderer) {
        unknownByKind[kind] = renderer
    }

    /// Resolve the renderer responsible for a projection.
    public func resolve(_ projection: EmbedKindProjection) -> KindRenderer {
        switch projection {
        case .shortNote:
            return shortNote ?? fallback
        case .article:
            return article ?? fallback
        case .highlight:
            return highlight ?? fallback
        case .profile:
            return profile ?? fallback
        case .unknown(let payload):
            return unknownByKind[payload.kind] ?? fallback
        }
    }
}

// MARK: - Default renderers

/// Default short-note renderer. Shows author + content text.
public struct DefaultShortNoteRenderer: KindRenderer {
    public init() {}
    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .shortNote(let note) = projection else { return AnyView(EmptyView()) }
        let author = note.authorDisplayName ?? shortHex(note.authorPubkey)
        return AnyView(
            VStack(alignment: .leading, spacing: 4) {
                Text("note · \(author)")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                Text(note.content)
                    .font(.callout)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
        )
    }
}

/// Default profile renderer. Shows display name + about line.
public struct DefaultProfileRenderer: KindRenderer {
    public init() {}
    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .profile(let p) = projection else { return AnyView(EmptyView()) }
        let label = p.displayName ?? shortHex(p.pubkey)
        return AnyView(
            VStack(alignment: .leading, spacing: 4) {
                Text("profile")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                Text(label).font(.headline)
                if let about = p.about, !about.isEmpty {
                    Text(about)
                        .font(.callout)
                        .foregroundStyle(.secondary)
                }
            }
        )
    }
}

/// Default article renderer. Shows title · author · summary. The richer
/// `ArticleEmbed` lives in `content-kind-30023/` and overrides this slot.
public struct DefaultArticleRenderer: KindRenderer {
    public init() {}
    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .article(let a) = projection else { return AnyView(EmptyView()) }
        let author = a.authorDisplayName ?? shortHex(a.authorPubkey)
        let title = a.title ?? "article"
        let summary = a.summary ?? ""
        return AnyView(
            VStack(alignment: .leading, spacing: 4) {
                Text("\(title) · \(author)")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                Text(summary)
                    .font(.callout)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
        )
    }
}

/// Default highlight renderer. Shows highlighted text + source author. The
/// richer `HighlightEmbed` lives in `content-kind-9802/`.
public struct DefaultHighlightRenderer: KindRenderer {
    public init() {}
    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .highlight(let h) = projection else { return AnyView(EmptyView()) }
        let author = h.authorDisplayName ?? shortHex(h.authorPubkey)
        return AnyView(
            VStack(alignment: .leading, spacing: 4) {
                Text("highlight · \(author)")
                    .font(.caption)
                    .foregroundStyle(.secondary)
